{
  "skill_name": "stock-explain",
  "evals": [
    {
      "id": 0,
      "prompt": "/stock-explain NVDA",
      "expected_output": "A five-section plain-English narrative explaining the NVDA model output. Should cover: (1) current price vs base IV with % gap, (2) FCF starting point with SBC strip explained, growth rate source, WACC, two-stage structure, (3) dominant sensitivity driver with dollar-impact numbers, (4) failure modes (playbook loaded for NVDA), (5) confidence level with reason. All acronyms spelled out on first use. No JSON block. No bullet lists. Flowing prose.",
      "files": [],
      "assertions": [
        {
          "id": "acronyms_spelled_out",
          "description": "All acronyms (FCF, DCF, WACC, SBC, IV, TTM) are spelled out on first use with definitions",
          "check": "string_contains_all",
          "expected": ["free cash flow", "discounted cash flow", "weighted-average cost of capital", "stock-based compensation"]
        },
        {
          "id": "five_sections_present",
          "description": "All five section headers are present",
          "check": "string_contains_all",
          "expected": ["bottom line", "How we got here", "driving the number", "could go wrong", "trust this"]
        },
        {
          "id": "dollar_figures_present",
          "description": "Concrete dollar figures appear (current price and at least one IV scenario)",
          "check": "regex_match",
          "pattern": "\\$[0-9]+"
        },
        {
          "id": "no_json_block",
          "description": "No JSON code block in the output",
          "check": "string_not_contains",
          "expected": "```json"
        },
        {
          "id": "report_date_shown",
          "description": "Report date is shown at the top",
          "check": "regex_match",
          "pattern": "202[0-9]-[0-9]{2}-[0-9]{2}"
        },
        {
          "id": "failure_modes_present",
          "description": "What-could-go-wrong section contains substantive risk content (not just generic)",
          "check": "string_contains_any",
          "expected": ["AI", "chip", "demand", "margin", "competitor", "competition", "slowdown"]
        }
      ]
    },
    {
      "id": 1,
      "prompt": "/stock-explain META",
      "expected_output": "A five-section plain-English narrative for META. Should explain META's FCF (large, advertising-driven), the growth assumption and WACC, what drives the spread between bear/base/bull, risks specific to META (ad spend, regulation, Reality Labs capex), and confidence level. All acronyms defined. No JSON. Flowing prose.",
      "files": [],
      "assertions": [
        {
          "id": "acronyms_spelled_out",
          "description": "All acronyms (FCF, WACC, SBC, IV) are spelled out on first use with definitions",
          "check": "string_contains_all",
          "expected": ["free cash flow", "weighted-average cost of capital", "stock-based compensation"]
        },
        {
          "id": "five_sections_present",
          "description": "All five section headers are present",
          "check": "string_contains_all",
          "expected": ["bottom line", "How we got here", "driving the number", "could go wrong", "trust this"]
        },
        {
          "id": "dollar_figures_present",
          "description": "Concrete dollar figures appear",
          "check": "regex_match",
          "pattern": "\\$[0-9]+"
        },
        {
          "id": "no_json_block",
          "description": "No JSON code block in the output",
          "check": "string_not_contains",
          "expected": "```json"
        },
        {
          "id": "no_bullet_lists",
          "description": "No markdown bullet lists (lines starting with - or *)",
          "check": "regex_not_match",
          "pattern": "^[\\-\\*] ",
          "flags": "multiline"
        }
      ]
    },
    {
      "id": 2,
      "prompt": "/stock-explain FAKE",
      "expected_output": "A clear error message telling the user no report was found for FAKE, and instructing them to run /stock-signal FAKE and /stock-model FAKE first. Should not crash or produce partial output.",
      "files": [],
      "assertions": [
        {
          "id": "error_message_shown",
          "description": "Output contains a helpful error message about no report being found",
          "check": "string_contains_any",
          "expected": ["No report found", "no report", "not found", "doesn't exist"]
        },
        {
          "id": "guidance_to_run_upstream",
          "description": "User is told to run /stock-signal and/or /stock-model first",
          "check": "string_contains_any",
          "expected": ["/stock-signal", "/stock-model", "stock-signal", "stock-model"]
        },
        {
          "id": "no_partial_output",
          "description": "No valuation sections appear when no report exists",
          "check": "string_not_contains",
          "expected": "## The bottom line"
        }
      ]
    }
  ]
}

